	UPDATE board 
	SET b_writer=#{b_writer}, 
        b_title=#{b_title}, 
        b_content=#{b_content}, 
        b_upload=#{b_upload}, 
        b_update=NOW()
    WHERE b_code=#{b_code} 
    AND b_pw=#{b_pw}
    AND m_code=#{m_code}

mapper.select:
SELECT ref FROM board
WHERE b_code = #{b_code}
AND b_pw = #{b_pw}
AND m_code = #{m_code}

	SELECT * FROM board
    ORDER BY ref DESC, re_step ASC
    LIMIT #{startRow}, #{pageSize}

SELECT * FROM board
